// Package imports:
import 'package:collection/collection.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/team_list_controller.dart';
import 'package:baseball_detector_flutter/controllers/user_accessible_contents_controller.dart';
import 'package:baseball_detector_flutter/data/models/app_store_plan.dart';
import 'package:baseball_detector_flutter/data/models/session.dart';
import 'package:baseball_detector_flutter/data/models/team.dart';
import 'package:baseball_detector_flutter/data/result.dart';
import 'package:baseball_detector_flutter/providers/profile_storage_provider.dart';
import 'package:baseball_detector_flutter/views/hooks/use_widget_ref.dart';

enum FabState {
  available,
  needsSubscription,
  unavailable,
}

FabState useFabState({
  required Session session,
  required String teamId,
  required bool canSubscribe,
}) {
  final ref = useWidgetRef();
  final userId = ref.watch(profileStorageProvider).getUserId();
  final accessibleContents =
      ref.watch(userAccessibleContentsControllerProvider);
  final teamList = ref.watch(teamListControllerProvider);

  final isRecordingAvailable = teamList.fold(
    loading: () => null,
    error: (_) => null,
    data: (teams) {
      final team = teams.where((team) => team.id == teamId).firstOrNull;

      // シングルユーザーチーム & Premium プラン & ボール解析数ゼロの場合は
      // サブスクリプションページへの遷移を抑制
      if (team != null) {
        final isPremiumWithNoRemainingBalls = team.isSingleUserTeam &&
            team.teamPlan?.plan?.planType == PlanType.premium &&
            team.teamPlanStatus == TeamPlanStatus.reachedLimit;

        if (isPremiumWithNoRemainingBalls) {
          return false; // unavailable として扱う
        }
      }

      return session.isVideoUploadableByUser(userId, accessibleContents) &&
          (team?.teamPlanStatus.canAnalyze ?? false);
    },
  );

  if (isRecordingAvailable == true) {
    return FabState.available;
  } else if (isRecordingAvailable == false && canSubscribe) {
    // Premium + ボールゼロの場合は needsSubscription にならないよう制御済み
    return FabState.needsSubscription;
  } else {
    return FabState.unavailable;
  }
}

